import { memo, useState, useEffect } from "react";
import { ShoppingBag, CalendarCheck, PenLine, ShieldCheck, ThumbsUp, ThumbsDown, BadgeCheck, X } from "lucide-react";
import { Link } from "react-router-dom";
import mapIcon from "@/assets/map-icon.png";
import certificationBadge from "@/assets/certification-badge.png";
import xiaoxiongLogo from "@/assets/xiaoxiong-logo-footer.png";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { useTranslation } from "react-i18next";

const useAboutUsReactions = (enabled: boolean) => {
  const { data: contentId } = useQuery({
    queryKey: ["about-us-content-id"],
    queryFn: async () => {
      const { data } = await supabase
        .from("about_us_content")
        .select("id")
        .limit(1)
        .single();
      return data?.id || null;
    },
    staleTime: 1000 * 60 * 10,
    enabled,
  });
  const { counts } = useStoryReactions(enabled && contentId ? contentId : undefined, "about_us");
  return counts;
};

const useCertificationReactions = (enabled: boolean) => {
  const { data: contentId } = useQuery({
    queryKey: ["certification-content-id"],
    queryFn: async () => {
      const { data } = await supabase
        .from("certification_content" as any)
        .select("id")
        .limit(1)
        .single();
      return (data as any)?.id || null;
    },
    staleTime: 1000 * 60 * 10,
    enabled,
  });
  const { counts } = useStoryReactions(enabled && contentId ? contentId : undefined, "certification");
  return counts;
};

const StatsDisplay = memo(({ stats, t }: { stats: { order_count: number; reserve_count: number; claimed_count: number }; t: (key: string) => string }) => {
  const [verifiedDialog, setVerifiedDialog] = useState(false);
  // Defer reaction queries by 2s to prioritize hero render
  const [reactionsReady, setReactionsReady] = useState(false);
  useEffect(() => {
    const timer = setTimeout(() => setReactionsReady(true), 2000);
    return () => clearTimeout(timer);
  }, []);

  const counts = useAboutUsReactions(reactionsReady);
  const certCounts = useCertificationReactions(reactionsReady);
  
  return (
    <div className="absolute top-16 sm:top-20 left-3 right-3 z-20">
      <div className="gap-2 w-full flex-col flex items-start justify-start">
        <div className="flex items-start justify-between w-full">
          <div className="flex flex-col gap-1.5">
            <span className="text-xl sm:text-2xl font-bold text-white drop-shadow-md">
              {t("home.hero.brandName")}
              <img 
                src={mapIcon} 
                alt="map icon" 
                width={28}
                height={28}
                loading="eager"
                decoding="async"
                className="inline-block w-6 sm:w-7 h-6 sm:h-7 object-contain ml-1 align-middle" 
              />
            </span>
            {stats.claimed_count > 0 && (
              <div className="flex items-center gap-1.5 text-xs sm:text-sm text-white/80 drop-shadow-md">
                <span>{t("home.stats.claimed")}</span>
                <span className="font-bold text-white">{stats.claimed_count}</span>
                <button
                  onClick={() => setVerifiedDialog(true)}
                  className="flex-shrink-0 flex items-center justify-center w-5 h-5 sm:w-6 sm:h-6 rounded-full bg-primary/90 backdrop-blur-sm shadow-soft hover:bg-primary transition-colors"
                  title={t("restaurants.verifiedStore")}
                >
                  <BadgeCheck className="w-3.5 h-3.5 sm:w-4 sm:h-4 text-primary-foreground" />
                </button>
              </div>
            )}
          </div>
          <div className="flex flex-col items-end gap-2">
            <a href="https://xiaoxiong.pt/" target="_blank" rel="noopener noreferrer">
              <img 
                src={xiaoxiongLogo} 
                alt="XIAOXIONG®" 
                className="h-3 sm:h-4 object-contain drop-shadow-md hover:opacity-80 transition-opacity" 
                loading="eager"
                decoding="async"
              />
            </a>
            <div className="flex items-center gap-2">
              <Link
                to="/about-us"
                className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-medium text-white bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/20 shadow-soft transition-all duration-300 hover:scale-105 group"
              >
                <PenLine className="w-4 h-4 text-primary drop-shadow-[0_0_4px_hsl(174_100%_25%/0.6)] group-hover:rotate-[-12deg] transition-transform duration-300" />
                <span>{t("home.hero.confession")}</span>
              </Link>
              {(counts.likes > 0 || counts.dislikes > 0) && (
                <div className="flex items-center gap-2 text-xs text-white/80 drop-shadow-md">
                  {counts.likes > 0 && (
                    <span className="inline-flex items-center gap-1">
                      <ThumbsUp className="w-3 h-3" /> {counts.likes}
                    </span>
                  )}
                  {counts.dislikes > 0 && (
                    <span className="inline-flex items-center gap-1">
                      <ThumbsDown className="w-3 h-3" /> {counts.dislikes}
                    </span>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
      {/* Verified Info Dialog */}
      <Dialog open={verifiedDialog} onOpenChange={setVerifiedDialog}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <BadgeCheck className="w-5 h-5 text-primary fill-primary/10" />
              {t("restaurants.verifiedStore")}
            </DialogTitle>
            <DialogDescription className="text-sm leading-relaxed pt-2">
              {t("restaurants.verifiedStoreDesc")}
            </DialogDescription>
          </DialogHeader>
        </DialogContent>
      </Dialog>
    </div>
  );
});
StatsDisplay.displayName = "StatsDisplay";

export default StatsDisplay;
