import { useState, useEffect, useRef, useCallback } from "react";
import { createPortal } from "react-dom";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { Camera, ThumbsUp, ThumbsDown, Share2, MessageSquare, Loader2, MapPin, ShieldCheck } from "lucide-react";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { useAuth } from "@/contexts/AuthContext";
import { useLoginRequired } from "@/hooks/useLoginRequired";
import { useComments } from "@/hooks/useComments";
import RestaurantComments from "@/components/RestaurantComments";
import IChingSection, { useAutoTranslateNarrative } from "@/components/IChingSection";
import DislikeReasonDialog from "@/components/DislikeReasonDialog";
import ClaimRestaurantDialog from "@/components/ClaimRestaurantDialog";

const ICHING_MARKERS = [
  "《易经",
  "易经·",
  "易经解读",
  "【易经",
  "卦意",
  "综合卦意",
  "《I Ching",
  "《I Ging",
  "《Le Livre",
  "《Kinh Dịch",
  "《역경",
  "『易経",
  "《И",
] as const;

function getIChingStartIndex(text: string) {
  let start = -1;

  for (const marker of ICHING_MARKERS) {
    const index = text.indexOf(marker);
    if (index >= 0 && (start < 0 || index < start)) {
      start = index;
    }
  }

  if (start < 0) {
    const genericIndex = text.indexOf("《");
    if (genericIndex > 80) return genericIndex;
  }

  return start;
}

function splitNarrativeAndIChing(text: string, fallbackIChing: string) {
  const sourceText = text || "";
  const iChingStart = getIChingStartIndex(sourceText);

  if (iChingStart < 0) {
    return {
      narrative: sourceText,
      iChing: fallbackIChing,
    };
  }

  const breakIndex = sourceText.lastIndexOf("\n", iChingStart);
  const cutPoint = breakIndex > 0 ? breakIndex : iChingStart;

  return {
    narrative: sourceText.slice(0, cutPoint).replace(/[\n\r\s]+$/, ""),
    iChing: sourceText.slice(iChingStart).trim() || fallbackIChing,
  };
}

const PhotoStoryDialog = ({ content, originalContentZh, onClose, templateId, restaurantId, restaurantName, michelinStars }: { content: string; originalContentZh?: string | null; onClose: () => void; templateId?: string; restaurantId?: string | null; restaurantName?: string | null; michelinStars?: number | null }) => {
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const scrollRef = useRef<HTMLDivElement>(null);
  const savedScrollY = useRef(0);

  // Lock body scroll - iOS WebView safe
  useEffect(() => {
    try {
      savedScrollY.current = window.scrollY || 0;
      document.body.style.position = 'fixed';
      document.body.style.top = `-${savedScrollY.current}px`;
      document.body.style.left = '0';
      document.body.style.right = '0';
      document.body.style.overflow = 'hidden';
    } catch (e) {
      console.error('Scroll lock error:', e);
    }
    
    return () => {
      try {
        document.body.style.position = '';
        document.body.style.top = '';
        document.body.style.left = '';
        document.body.style.right = '';
        document.body.style.overflow = '';
        window.scrollTo(0, savedScrollY.current);
      } catch (e) {
        console.error('Scroll restore error:', e);
      }
    };
  }, []);

  // Prevent touch events from leaking to background on iOS WebView
  useEffect(() => {
    const preventBgScroll = (e: TouchEvent) => {
      const target = e.target as HTMLElement;
      if (scrollRef.current?.contains(target)) return;
      e.preventDefault();
    };
    
    document.addEventListener('touchmove', preventBgScroll, { passive: false });
    return () => {
      document.removeEventListener('touchmove', preventBgScroll);
    };
  }, []);
  
  // Keep narrative in current language, but always keep I Ching source in Chinese
  const defaultIChingZh = i18n.getFixedT("zh")("home.hero.photoStoryIChing", '《易经·井》：\u201C井养而不穷也。\u201D —— 一口井滋养着周围的人，从不枯竭。这个街角的拉面店正如一口古井，日复一日为邻里提供温暖与慰藉，维系着社区最朴素的纽带。');
  const { narrative: narrativeContent } = splitNarrativeAndIChing(content || "", defaultIChingZh);
  const { iChing: iChingText } = splitNarrativeAndIChing(originalContentZh || "", defaultIChingZh);
  
  const { translatedNarrative, isAutoTranslating } = useAutoTranslateNarrative(narrativeContent || null, i18n.language);
  const { counts, userReaction, toggleReaction } = useStoryReactions(templateId, "template");
  const { user } = useAuth();
  const { requireLogin } = useLoginRequired();
  const [showComments, setShowComments] = useState(false);
  const [showDislikeDialog, setShowDislikeDialog] = useState(false);
  const [showClaimDialog, setShowClaimDialog] = useState(false);
  const { data: storyComments } = useComments(templateId || "", "story", { enabled: !!templateId });
  const commentsCount = storyComments?.reduce((acc: number, c: any) => acc + 1 + (c.replies?.length || 0), 0) || 0;

  const handleShare = useCallback(async () => {
    try {
      if (navigator.share) {
        await navigator.share({ title: t("home.hero.photoStory"), url: window.location.href });
      } else if (navigator.clipboard) {
        await navigator.clipboard.writeText(window.location.href);
        toast.success(t("common.linkCopied", "链接已复制"));
      }
    } catch (e) {
      console.warn('Share failed:', e);
    }
  }, [t]);

  const handleReaction = useCallback((type: "like" | "dislike") => {
    try {
      if (type === "dislike" && userReaction !== "dislike") {
        setShowDislikeDialog(true);
        return;
      }
      toggleReaction.mutate({ type });
    } catch (e) {
      console.error('Reaction error:', e);
    }
  }, [userReaction, toggleReaction]);

  const handleVisitStore = useCallback(() => {
    try {
      onClose();
      setTimeout(() => {
        navigate(`/restaurant/${restaurantId}`);
      }, 50);
    } catch (e) {
      console.error('Navigation error:', e);
    }
  }, [onClose, navigate, restaurantId]);

  return createPortal(
    <>
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center"
      style={{ touchAction: 'none' }}
      onClick={onClose}
    >
      {/* Overlay - NO backdrop-blur for iOS WebView */}
      <div className="absolute inset-0 bg-black/70" style={{ willChange: 'auto' }} />
      
      <div 
        className="relative max-w-lg w-full mx-4 bg-background rounded-2xl shadow-2xl overflow-hidden animate-fade-in"
        style={{ maxHeight: '85dvh', display: 'flex', flexDirection: 'column' }}
        onClick={(e) => e.stopPropagation()}
      >
        <div 
          ref={scrollRef}
          className="p-6 sm:p-8 space-y-4 overflow-y-auto overscroll-contain"
          style={{ 
            WebkitOverflowScrolling: 'touch',
            flex: 1,
            minHeight: 0,
          }}
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
              <Camera className="w-5 h-5 text-primary" />
            </div>
            <div className="min-w-0 flex-1">
              <h3 className="text-lg font-bold text-foreground leading-tight">{t("home.hero.photoStory")}</h3>
              {restaurantName && (
                <div className="flex items-center gap-1.5 mt-0.5 min-w-0">
                  {(michelinStars ?? 0) > 0 && (
                    <span className="flex items-center gap-0.5 shrink-0" title={`${michelinStars} Michelin Star`}>
                      {Array.from({ length: Math.min(michelinStars ?? 0, 3) }).map((_, i) => (
                        <svg key={i} viewBox="0 0 24 24" className="w-3.5 h-3.5" aria-hidden="true">
                          <g fill="#E4002B">
                            {[0, 60, 120, 180, 240, 300].map((deg) => (
                              <ellipse key={deg} cx="12" cy="6" rx="3" ry="5" transform={`rotate(${deg} 12 12)`} />
                            ))}
                            <circle cx="12" cy="12" r="2.2" fill="#FFF" />
                          </g>
                        </svg>
                      ))}
                    </span>
                  )}
                  <p className="text-sm text-muted-foreground truncate">{restaurantName}</p>
                </div>
              )}
            </div>
          </div>
          {isAutoTranslating && !translatedNarrative && (
            <div className="flex items-center gap-2 mb-1 text-xs text-muted-foreground">
              <Loader2 className="h-3 w-3 animate-spin" />
              <span>{t("translate.translating", "翻译中...")}</span>
            </div>
          )}
          <p className="text-sm sm:text-base text-muted-foreground leading-relaxed">
            {translatedNarrative || narrativeContent}
          </p>
          <div className="pt-3 border-t border-border/50">
            <IChingSection text={iChingText} />
          </div>
          <div className="flex items-center justify-center gap-4 pt-2 border-t border-border/50">
            <button onClick={() => handleReaction("like")}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                userReaction === "like" ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}>
              <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
              {counts.likes > 0 && <span>{counts.likes}</span>}
            </button>
            <button onClick={() => handleReaction("dislike")}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                userReaction === "dislike" ? "bg-destructive/15 text-destructive" : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
              }`}>
              <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
              {counts.dislikes > 0 && <span>{counts.dislikes}</span>}
            </button>
            <button onClick={handleShare}
              className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95">
              <Share2 className="w-4 h-4" />
            </button>
            <button onClick={() => setShowComments(!showComments)}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}>
              <MessageSquare className="w-4 h-4" />
              {commentsCount > 0 && <span>{commentsCount}</span>}
            </button>
          </div>
          {showComments && templateId && (
            <div className="mt-2">
              <RestaurantComments targetId={templateId} targetType="story" />
            </div>
          )}
          {restaurantId && (
            <div className="pt-1 flex flex-col sm:flex-row gap-2">
              <Button
                variant="outline"
                size="sm"
                className="flex-1 gap-2 rounded-full border-primary/30 text-primary hover:bg-primary/10 hover:border-primary/50"
                onClick={handleVisitStore}
              >
                <MapPin className="w-4 h-4" />
                {t("home.hero.visitLandmark", "查看餐厅")}
              </Button>
              <Button
                size="sm"
                className="flex-1 gap-2 rounded-full"
                onClick={() => { if (requireLogin()) setShowClaimDialog(true); }}
              >
                <ShieldCheck className="w-4 h-4" />
                {t("photoStory.claimStore", "认领")}
              </Button>
            </div>
          )}
          <div className="flex items-center justify-end">
            <Button onClick={onClose} className="rounded-full px-6">
              {t("common.close", "关闭")}
            </Button>
          </div>
        </div>
      </div>
    </div>
    <DislikeReasonDialog
      open={showDislikeDialog}
      onOpenChange={setShowDislikeDialog}
      onSubmit={(reason) => {
        try { toggleReaction.mutate({ type: "dislike", reason }); } catch (e) { console.error(e); }
      }}
    />
    {restaurantId && (
      <ClaimRestaurantDialog
        open={showClaimDialog}
        onOpenChange={setShowClaimDialog}
        restaurant={{ id: restaurantId, name: restaurantName || "" }}
      />
    )}
    </>,
    document.body
  );
};

export default PhotoStoryDialog;
